select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v, postgres.users as u where p.id = pl.postid and p.id = ph.postid and p.id = c.postid and u.id = c.userid and u.id = v.userid and c.creationdate<=timestamp '2014-09-11 13:24:22' and p.posttypeid=1 and p.score=2 and p.favoritecount<=12 and pl.creationdate>=timestamp '2010-08-13 11:42:08' and pl.creationdate<=timestamp '2014-08-29 00:27:05' and ph.creationdate>=timestamp '2011-01-03 23:47:35' and ph.creationdate<=timestamp '2014-09-08 12:48:36' and v.creationdate>=timestamp '2010-07-27 00:00:00' and u.reputation>=1 and u.downvotes>=0;
